  /**
   * 호버 이벤트 설정 (데스크톱 전용 - 모바일에서는 수동 닫기만)
   */
  setupHoverEvents(targetElement) {
    if (import_obsidian13.Platform.isMobile) {
      Logger.debug("\u{1F4F1} \uBAA8\uBC14\uC77C: \uD638\uBC84 \uC774\uBCA4\uD2B8 \uC124\uC815 \uC0DD\uB7B5 - \uC218\uB3D9 \uB2EB\uAE30\uB9CC \uD5C8\uC6A9");
      return;
    }
    let hideTimeout;
    let isHovering = false;
    const startHideTimer = () => {
      if (hideTimeout)
        window.clearTimeout(hideTimeout);
      hideTimeout = window.setTimeout(() => {
        if (!isHovering) {
          Logger.debug("\u{1F50D} \uD234\uD301 \uC790\uB3D9 \uC228\uAE40");
          this.hide(true);
        }
      }, 2e3);
    };
    const cancelHideTimer = () => {
      if (hideTimeout) {
        window.clearTimeout(hideTimeout);
        hideTimeout = void 0;
      }
    };
    const setHovering = (hovering) => {
      isHovering = hovering;
      if (hovering) {
        cancelHideTimer();
        Logger.debug("\u{1F50D} \uD638\uBC84 \uC2DC\uC791 - \uD0C0\uC774\uBA38 \uCDE8\uC18C");
      } else {
        Logger.debug("\u{1F50D} \uD638\uBC84 \uC885\uB8CC - \uD0C0\uC774\uBA38 \uC2DC\uC791");
        startHideTimer();
      }
    };
    const handleMouseEvent = (e) => {
      if (!this.tooltip)
        return;
      const target = e.target;
      const isOnTarget = targetElement.contains(target) || targetElement === target;
      const isOnTooltip = this.tooltip.contains(target) || this.tooltip === target;
      setHovering(isOnTarget || isOnTooltip);
    };
    const onMouseMove = (e) => handleMouseEvent(e);
    const onMouseOver = (e) => handleMouseEvent(e);
    const onMouseClick = (e) => {
      if (!this.tooltip)
        return;
      const target = e.target;
      const isOnTarget = targetElement.contains(target) || targetElement === target;
      const isOnTooltip = this.tooltip.contains(target) || this.tooltip === target;
      if (!isOnTarget && !isOnTooltip) {
        Logger.debug("\u{1F50D} \uC678\uBD80 \uD074\uB9AD - \uC989\uC2DC \uC228\uAE40");
        this.hide(true);
      }
    };
    activeDocument.addEventListener("mousemove", onMouseMove, { passive: true });
    activeDocument.addEventListener("mouseover", onMouseOver, { passive: true });
    activeDocument.addEventListener("click", onMouseClick);
    startHideTimer();
    this.tooltip._cleanup = () => {
      activeDocument.removeEventListener("mousemove", onMouseMove);
      activeDocument.removeEventListener("mouseover", onMouseOver);
      activeDocument.removeEventListener("click", onMouseClick);
      if (hideTimeout)
        window.clearTimeout(hideTimeout);
      Logger.debug("\u{1F50D} \uD638\uBC84 \uC774\uBCA4\uD2B8 \uC815\uB9AC \uC644\uB8CC");
    };
  }
